private object Http {
    data class Response(val code: Int, val body: String)

    fun get(url: String, headers: Map<String, String> = emptyMap()): Response {
        val conn = (java.net.URL(url).openConnection() as java.net.HttpURLConnection).apply {
            requestMethod = "GET"
            instanceFollowRedirects = false
            connectTimeout = 15000
            readTimeout = 15000
            headers.forEach { (k, v) -> setRequestProperty(k, v) }
        }
        return conn.useAndRead()
    }

    fun formUrlEncodedPost(url: String, params: Map<String, String>, headers: Map<String, String> = emptyMap()): Response {
        val body = params.entries.joinToString("&") { (k, v) ->
            "${Uri.encode(k)}=${Uri.encode(v)}"
        }
        val bytes = body.toByteArray(Charsets.UTF_8)
        val conn = (java.net.URL(url).openConnection() as java.net.HttpURLConnection).apply {
            requestMethod = "POST"
            instanceFollowRedirects = false
            doOutput = true
            connectTimeout = 15000
            readTimeout = 15000
            setRequestProperty("Content-Type", "application/x-www-form-urlencoded")
            setRequestProperty("Content-Length", bytes.size.toString())
            headers.forEach { (k, v) -> setRequestProperty(k, v) }
        }
        conn.outputStream.use { it.write(bytes) }
        return conn.useAndRead()
    }

    private fun java.net.HttpURLConnection.useAndRead(): Response {
        val code = responseCode
        val stream = try {
            if (code in 200..299) inputStream else errorStream
        } catch (_: Throwable) {
            null
        }
        val body = stream?.bufferedReader(Charsets.UTF_8)?.use { it.readText() } ?: ""
        disconnect()
        return Response(code, body)
    }
}

private object Json {
    fun parseObject(json: String): JsonObject {
        val trimmed = json.trim()
        if (!trimmed.startsWith("{") || !trimmed.endsWith("}")) return JsonObject(emptyMap())
        val map = LinkedHashMap<String, String>()
        val tokens = tokenize(trimmed.substring(1, trimmed.length - 1))
        var i = 0
        while (i < tokens.size) {
            val key = tokens[i]
            if (i + 2 >= tokens.size) break
            val colon = tokens[i + 1]
            val value = tokens[i + 2]
            if (colon != ":") break
            map[unquote(key)] = unquote(value)
            i += 3
            if (i < tokens.size && tokens[i] == ",") i++
        }
        return JsonObject(map)
    }

    private fun tokenize(s: String): List<String> {
        val out = ArrayList<String>()
        var i = 0
        while (i < s.length) {
            val c = s[i]
            when {
                c.isWhitespace() -> i++
                c == '"' -> {
                    val sb = StringBuilder()
                    sb.append(c)
                    i++
                    var escaped = false
                    while (i < s.length) {
                        val ch = s[i]
                        sb.append(ch)
                        if (escaped) {
                            escaped = false
                        } else if (ch == '\\') {
                            escaped = true
                        } else if (ch == '"') {
                            i++
                            break
                        }
                        i++
                    }
                    out.add(sb.toString())
                }
                c == ':' || c == ',' -> {
                    out.add(c.toString())
                    i++
                }
                else -> {
                    val start = i
                    while (i < s.length && !s[i].isWhitespace() && s[i] != ':' && s[i] != ',') i++
                    out.add(s.substring(start, i))
                }
            }
        }
        return out
    }

    private fun unquote(token: String): String {
        val t = token.trim()
        if (t.startsWith("\"") && t.endsWith("\"") && t.length >= 2) {
            return t.substring(1, t.length - 1)
                .replace("\\\"", "\"")
                .replace("\\n", "\n")
                .replace("\\r", "\r")
                .replace("\\t", "\t")
                .replace("\\\\", "\\")
        }
        return t
    }

    class JsonObject(private val map: Map<String, String>) {
        operator fun get(key: String): String? = map[key]
        fun toMap(): Map<String, String> = map
    }
